const tarefas = $input.all().map(item => item.json);

// === EMAILS REAIS DOS RESPONSÁVEIS ===
// Quando os emails do CRM forem corrigidos, basta atualizar aqui.
const responsaveis = {
  1: { nome: "João Pedro", email: "joaopedro.fg.baldo@gmail.com" },
  5: { nome: "Júlia", email: "EMAIL_REAL_DA_JULIA@gmail.com" }
  // Novo vendedor? Só adicionar: 6: { nome: "Fulano", email: "fulano@gmail.com" }
};

const hojeData = new Date();
hojeData.setUTCHours(hojeData.getUTCHours() - 3);
const hojeStr = hojeData.toISOString().split('T')[0];

// Agrupa tarefas por user_id
const tarefasPorUsuario = {};

for (const t of tarefas) {
  const uid = t.user_id;
  if (!uid || !responsaveis[uid]) continue;

  if (!tarefasPorUsuario[uid]) {
    tarefasPorUsuario[uid] = { atrasadas: [], hoje: [] };
  }

  if (!t.data_vencimento) continue;

  const vencData = new Date(t.data_vencimento);
  vencData.setUTCHours(vencData.getUTCHours() - 3);
  const vencStr = vencData.toISOString().split('T')[0];

  if (vencStr < hojeStr) {
    tarefasPorUsuario[uid].atrasadas.push(t);
  } else if (vencStr === hojeStr) {
    tarefasPorUsuario[uid].hoje.push(t);
  }
}

// Monta um item de saída POR RESPONSÁVEL
const output = [];

for (const [uid, grupo] of Object.entries(tarefasPorUsuario)) {
  const user = responsaveis[uid];
  const totalEnviar = grupo.atrasadas.length + grupo.hoje.length;

  let html = `<div style="font-family: Arial, sans-serif; color: #333; line-height: 1.6; max-width: 600px; margin: auto; border: 1px solid #ddd; padding: 20px; border-radius: 8px;">`;
  html += `<h2 style="color: #FF5A5F;">Bom dia, ${user.nome}! ☀️</h2>`;
  html += `<p>Aqui está o resumo das <b>suas</b> atividades para hoje. Vamos com tudo!</p>`;

  if (grupo.atrasadas.length > 0) {
    html += `<h3 style="color: #D32F2F; border-bottom: 2px solid #D32F2F; padding-bottom: 5px;">🚨 Tarefas Atrasadas (Urgência Máxima)</h3><ul style="padding-left: 20px;">`;
    for (const t of grupo.atrasadas) {
      const vencData = new Date(t.data_vencimento);
      vencData.setUTCHours(vencData.getUTCHours() - 3);
      const parts = vencData.toISOString().split('T')[0].split('-');
      const dataBR = `${parts[2]}/${parts[1]}/${parts[0]}`;
      const horario = vencData.toISOString().split('T')[1].substring(0, 5);
      const desc = t.descricao ? `<br><span style="color: #555;"><i>"${t.descricao}"</i></span>` : '';
      html += `<li style="margin-bottom: 12px;"><b>${t.titulo}</b>${desc}<br><small style="color: #777;">Vencimento original: ${dataBR} às ${horario} | ID Lead: #${t.lead_id || 'N/A'}</small></li>`;
    }
    html += `</ul>`;
  }

  if (grupo.hoje.length > 0) {
    html += `<h3 style="color: #1976D2; border-bottom: 2px solid #1976D2; padding-bottom: 5px;">📅 Tarefas para Hoje</h3><ul style="padding-left: 20px;">`;
    for (const t of grupo.hoje) {
      const vencData = new Date(t.data_vencimento);
      vencData.setUTCHours(vencData.getUTCHours() - 3);
      const horario = vencData.toISOString().split('T')[1].substring(0, 5);
      const desc = t.descricao ? `<br><span style="color: #555;"><i>"${t.descricao}"</i></span>` : '';
      html += `<li style="margin-bottom: 12px;"><b>${t.titulo}</b>${desc}<br><small style="color: #777;">Horário: ${horario} | ID Lead: #${t.lead_id || 'N/A'}</small></li>`;
    }
    html += `</ul>`;
  } else if (grupo.atrasadas.length === 0) {
    html += `<p style="color: #2E7D32; font-weight: bold;">✅ Não há tarefas agendadas para hoje!</p>`;
  }

  html += `<hr style="border: 0; border-top: 1px solid #eee; margin: 20px 0;">`;
  html += `<p style="font-size: 12px; color: #999;">Por favor, atualize o status no CRM assim que concluir.</p></div>`;

  output.push({
    json: {
      html_email: html,
      total_enviar: totalEnviar,
      email_destino: user.email,
      nome_responsavel: user.nome
    }
  });
}

return output;
